const crypto = require('crypto');
const binary = $input.first().binary.data;
const content = Buffer.from(binary.data, 'base64').toString('utf8');
const rows = [];
for (const line of content.split(/\r?\n/)) {
  const rawLine = line.trim();
  if (!rawLine) continue;
  const event = JSON.parse(rawLine);
  rows.push({
    json: {
      event_hash: crypto.createHash('sha256').update(rawLine).digest('hex'),
      event_uuid: event.uuid || null,
      timestamp_evento: event.timestamp || null,
      eventid: event.eventid || null,
      session_id: event.session || null,
      sensor: event.sensor || null,
      src_ip: event.src_ip || null,
      src_port: event.src_port || null,
      username: event.username || null,
      password: event.password || null,
      command_input: event.input || null,
      url: event.url || null,
      shasum: event.shasum || null,
      raw_event: event
    }
  });
}
return rows;
